-- ============================================================
-- 음성소망의료재단 + 현대병원 직원 데이터 시드
-- 소망병원: SM-0001 ~ SM-137, 현대병원: HD-0001 ~ HD-69
-- ============================================================

CREATE TABLE IF NOT EXISTS corporations (
  id          uuid PRIMARY KEY,
  name        text NOT NULL,
  short_code  text NOT NULL UNIQUE,
  created_at  timestamptz DEFAULT now()
);

ON CONFLICT (short_code) DO NOTHING;

CREATE TABLE IF NOT EXISTS staff_directory (
  id                 uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  employee_id        text UNIQUE NOT NULL,
  corporation_id     uuid REFERENCES corporations(id),
  full_name          text NOT NULL,
  parent_dept        text,
  department         text,
  position           text,
  job_role           text,
  phone              text,
  is_global_employee boolean DEFAULT false,
  profile_id         uuid,
  created_at         timestamptz DEFAULT now()
);

ALTER TABLE staff_directory ENABLE ROW LEVEL SECURITY;
CREATE POLICY "staff_directory_open" ON staff_directory FOR ALL USING (true);

-- 소망병원 직원 (SM-0001 ~ SM-137)

-- 현대병원 직원 (HD-0001 ~ HD-69, 이강표·김한수 제외)

-- 기존 3명 profiles 업데이트
UPDATE profiles SET corporation_id = 'c1000000-0000-0000-0000-000000000001', employee_id = 'SM-0001' WHERE id = '271b25cb-84d5-43ea-9056-559fd75f4de5'; -- 이강표
UPDATE profiles SET corporation_id = 'c1000000-0000-0000-0000-000000000001', employee_id = 'SM-0016' WHERE id = '0cab6761-8cb2-44ab-bb24-00acebe9dfde'; -- 한기석
UPDATE profiles SET corporation_id = 'c1000000-0000-0000-0000-000000000001', employee_id = 'SM-0029' WHERE id = '460358a6-85aa-4418-bd6b-f1127aa37646'; -- 윤민주
UPDATE profiles SET is_global_viewer = true WHERE id = '271b25cb-84d5-43ea-9056-559fd75f4de5'; -- 이강표 전법인 접근
